function solve(points) {
    const n = points.length;
    const slopeMap = new Map();

    // Function to calculate the slope between two points
    function getSlope(p1, p2) {
        const dx = p2[0] - p1[0];
        const dy = p2[1] - p1[1];
        if (dx === 0 && dy === 0) return null; // same point
        if (dx === 0) return Infinity; // vertical line
        return dy / dx;
    }

    // Function to count the number of pairs with the same slope
    function countPairs(slope, points) {
        let count = 0;
        for (let i = 0; i < points.length; i++) {
            for (let j = i + 1; j < points.length; j++) {
                if (getSlope(points[i], points[j]) === slope) {
                    count++;
                }
            }
        }
        return count;
    }

    // Count the number of pairs with the same slope
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const slope = getSlope(points[i], points[j]);
            if (slope !== null) {
                const key = slope.toString();
                if (!slopeMap.has(key)) {
                    slopeMap.set(key, 0);
                }
                slopeMap.set(key, slopeMap.get(key) + 1);
            }
        }
    }

    // Calculate the number of trapezoids
    let trapezoidCount = 0;
    for (const [slope, count] of slopeMap.entries()) {
        const pairs = countPairs(slope, points);
        trapezoidCount += (count * (count - 1)) / 2;
    }

    return trapezoidCount;
}

